#include <iostream>

using namespace std;

int add(int a, int b)
{
    return a + b;
}

double add(double a, double b)
{
    return a + b;
}

int main()
{
    cout << add(2, 3) << endl;
    cout << add(2.5, 3.5) << endl;

    return 0;
}

int add(int a, int b)
{
    return a + b;
}

int add(int a, int b, int c)
{
    return a + b + c;
}

void show(int n) { cout << "int"; }
void show(double n) { cout << "double"; }

show(5);    // calls show(int) — exact match
show(5.0);  // calls show(double) — exact match
show('A');  // which one? char can convert to either...

